#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1010;bool a[N][N];int n,P[N],v[N];
inline bool cmp(const int &x,const int &y){return v[x]>v[y];}
int main()
{
	n=read();rep(1,n,i)v[i]=read(),P[i]=i;std::sort(P+1,P+n+1,[&](int x,int y){return v[x]>v[y];});
	rep(1,n,i){int cur=i,tmp=v[P[i]];while(tmp--){a[P[i]][cur]=1;cur=(cur==n+1?1:cur+1);}}
	printf("%d\n",n+1);rep(1,n+1,i){rep(1,n,j)putchar(a[j][i]?'1':'0');putchar('\n');}
}
